### 8. **src/renderer/src/hooks/useTasks.ts** — Full Hook with `markComplete`

```typescript
import { useState, useCallback } from 'react'
import type { Task, CreateTaskPayload, UpdateTaskPayload } from '@shared/types'
import * as ipc from '@renderer/lib/ipc'
import { arrayMove } from '@dnd-kit/sortable'

export function useTasks(opts?: { categoryId?: number; includeComplete?: boolean }) {
  const [tasks, setTasks] = useState<Task[]>([])
  const [loading, setLoading] = useState(false)

  const refresh = useCallback(async () => {
    setLoading(true)
    try {
      setTasks(await ipc.getAllTasks(opts))
    } finally {
      setLoading(false)
    }
  }, [opts?.categoryId, opts?.includeComplete])

  const addTask = useCallback(async (payload: CreateTaskPayload) => {
    const newTask = await ipc.createTask(payload)
    setTasks((prev) => [...prev, newTask])
    return newTask
  }, [])

  const editTask = useCallback(async (payload: UpdateTaskPayload) => {
    const updated = await ipc.updateTask(payload)
    setTasks((prev) => prev.map((t) => (t.id === updated.id ? updated : t)))
    return updated
  }, [])

  const removeTask = useCallback(async (id: number) => {
    await ipc.deleteTask(id)
    setTasks((prev) => prev.filter((t) => t.id !== id))
  }, [])

  /**
   * Optimistically reorder tasks by dragging.
   * oldIndex/newIndex are positions in the current `tasks` array.
   */
  const reorder = useCallback(
    async (oldIndex: number, newIndex: number) => {
      const reordered = arrayMove(tasks, oldIndex, newIndex)
      setTasks(reordered) // optimistic update
      try {
        await ipc.reorderTasks(reordered.map((t) => t.id))
      } catch {
        // Revert on failure
        setTasks(tasks)
      }
    },
    [tasks]
  )

  const markComplete = useCallback(async (id: number) => {
    await ipc.completeTask(id)
    // Remove from list (complete tasks are hidden by default); caller can refresh if needed
    setTasks((prev) => prev.filter((t) => t.id !== id))
  }, [])

  return { tasks, loading, refresh, addTask, editTask, removeTask, reorder, markComplete }
}
```

**Note:** `markComplete` at line 54 just calls IPC and removes from UI. No direct gamification hook here yet.

